import React from 'react';
import styles from './HeroBanner.module.css';

function HeroBanner() {
  return (
    <section className={styles.hero}>
      {/* Left model image placeholder */}
      <div className={`${styles.panel} ${styles.panelLeft}`}>
        <div className={styles.modelPlaceholderLeft} />
      </div>

      {/* Center overlay text */}
      <div className={styles.overlay}>
        <p className={styles.season}>2026</p>
        <p className={styles.title}>Spring Summer Womenswear Collection</p>
        <a href="#!" className={styles.viewBtn}>VIEW</a>
      </div>

      {/* Right model image placeholder */}
      <div className={`${styles.panel} ${styles.panelRight}`}>
        <div className={styles.modelPlaceholderRight} />
      </div>

      {/* Scroll indicator */}
      <div className={styles.scrollIndicator}>
        <span className={styles.scrollText}>SCROLL</span>
        <div className={styles.scrollLine} />
      </div>
    </section>
  );
}

export default HeroBanner;
